import json,glob,os,statistics as st
rows=[]
for f in glob.glob('data/test_data/cleaned_data/*.jsonl'):
    m=os.path.basename(f)[:-6]
    rr=f'results/race/{m}/raw_results.jsonl'
    if m=='reference' or not os.path.exists(rr): continue
    for line in open(rr):
        o=json.loads(line)
        if str(o['id'])=='72':
            rows.append(o)
def corr(a,b):
    ma,mb=st.mean(a),st.mean(b)
    return sum((x-ma)*(y-mb) for x,y in zip(a,b))/(len(a)*st.pstdev(a)*st.pstdev(b))
IF=[r['instruction_following'] for r in rows]
for d in ['comprehensiveness','insight','readability','overall_score']:
    print('corr(IF,%s) = %.3f'%(d,corr(IF,[r[d] for r in rows])))
print('IF sd=%.4f  range %.3f-%.3f'%(st.pstdev(IF),min(IF),max(IF)))
EOF

